diff --git a/scripts/backfill-pr-orgscoped.ts b/scripts/backfill-pr-orgscoped.ts
new file mode 100644
index 000000000..a54f75cb4
--- /dev/null
+++ b/scripts/backfill-pr-orgscoped.ts
@@ -0,0 +1,361 @@
+#!/usr/bin/env node
+/**
+ * Migrate PR review/finding subcollections from the dead top-level
+ * `pullRequests/{prId}/reviews/...` tree to the canonical org-scoped tree
+ * `organizations/{orgId}/pullRequests/{prId}/reviews/...`.
+ *
+ * Why
+ * ---
+ * The CRREAD-1 refactor split writes (org-scoped) from reads (top-level) and
+ * then never finished the bridging. Reviews from the MCP record_* tools landed
+ * at the top-level path, but the dashboard reads from the org-scoped path, so
+ * historical reviews were invisible. After PR #XXXX every code path uses the
+ * org-scoped tree; this script copies the orphaned historical data over and
+ * recomputes the denormalised parent-PR fields (`stats.reviewCount`,
+ * `latestReviewId`, `hasFindingsMin`).
+ *
+ * Idempotent: re-running skips reviews/findings that already exist at the
+ * target path. Source documents are left in place by default — pass
+ * `--delete-source` to remove them after a successful copy.
+ *
+ * Usage:
+ *   # Dry run (default — prints what would change, no writes):
+ *   npx tsx scripts/backfill-pr-orgscoped.ts
+ *
+ *   # Actually write:
+ *   npx tsx scripts/backfill-pr-orgscoped.ts --apply
+ *
+ *   # Apply + delete source (run only after verifying the dashboard renders):
+ *   npx tsx scripts/backfill-pr-orgscoped.ts --apply --delete-source
+ *
+ * Environment:
+ *   FIRESTORE_EMULATOR_HOST  set to 127.0.0.1:8088 for local dev
+ *   GCLOUD_PROJECT           GCP project id (defaults to aictrl-prod)
+ */
+
+import { getApps, initializeApp } from 'firebase-admin/app';
+import { getFirestore, type Firestore, type DocumentData } from 'firebase-admin/firestore';
+import {
+  CODE_REVIEW_SEVERITY_ORDER,
+  type CodeReview,
+  type CodeReviewFinding,
+  type CodeReviewSeverity,
+  type PullRequest,
+} from '../server/state/types.js';
+
+const APPLY = process.argv.includes('--apply');
+const DELETE_SOURCE = process.argv.includes('--delete-source');
+const PROJECT_ID = process.env.GCLOUD_PROJECT ?? 'aictrl-prod';
+
+if (DELETE_SOURCE && !APPLY) {
+  console.error('--delete-source requires --apply');
+  process.exit(1);
+}
+
+if (!getApps().length) {
+  initializeApp({ projectId: PROJECT_ID });
+}
+
+const db: Firestore = getFirestore();
+
+interface Stats {
+  reviewsScanned: number;
+  reviewsCopied: number;
+  reviewsAlreadyAtTarget: number;
+  findingsCopied: number;
+  findingsAlreadyAtTarget: number;
+  parentPrsRecomputed: number;
+  parentPrMissing: number;
+  sourceDeleted: number;
+  errors: number;
+}
+
+const stats: Stats = {
+  reviewsScanned: 0,
+  reviewsCopied: 0,
+  reviewsAlreadyAtTarget: 0,
+  findingsCopied: 0,
+  findingsAlreadyAtTarget: 0,
+  parentPrsRecomputed: 0,
+  parentPrMissing: 0,
+  sourceDeleted: 0,
+  errors: 0,
+};
+
+/**
+ * Detect whether a review document path is the legacy top-level form
+ * `pullRequests/{prId}/reviews/{reviewId}` rather than the canonical
+ * `organizations/{orgId}/pullRequests/{prId}/reviews/{reviewId}` form.
+ */
+function isLegacyPath(docPath: string): boolean {
+  return docPath.startsWith('pullRequests/');
+}
+
+async function copyReview(
+  orgId: string,
+  prId: string,
+  reviewId: string,
+  sourceData: DocumentData,
+): Promise<{ copied: boolean; alreadyAtTarget: boolean }> {
+  const targetRef = db
+    .collection('organizations')
+    .doc(orgId)
+    .collection('pullRequests')
+    .doc(prId)
+    .collection('reviews')
+    .doc(reviewId);
+
+  const targetSnap = await targetRef.get();
+  if (targetSnap.exists) {
+    return { copied: false, alreadyAtTarget: true };
+  }
+  if (APPLY) {
+    await targetRef.set(sourceData);
+  }
+  // In dry-run we surface intent: nothing was written, but a write WOULD have
+  // happened. Callers only increment "copied" counters on APPLY (see main).
+  return { copied: APPLY, alreadyAtTarget: false };
+}
+
+async function copyFindings(
+  orgId: string,
+  prId: string,
+  reviewId: string,
+  sourcePath: string,
+): Promise<void> {
+  const sourceFindings = await db.collection(`${sourcePath}/findings`).get();
+  for (const findingDoc of sourceFindings.docs) {
+    const targetRef = db
+      .collection('organizations')
+      .doc(orgId)
+      .collection('pullRequests')
+      .doc(prId)
+      .collection('reviews')
+      .doc(reviewId)
+      .collection('findings')
+      .doc(findingDoc.id);
+
+    const targetSnap = await targetRef.get();
+    if (targetSnap.exists) {
+      stats.findingsAlreadyAtTarget++;
+      continue;
+    }
+    if (APPLY) {
+      await targetRef.set(findingDoc.data());
+      stats.findingsCopied++;
+    }
+  }
+}
+
+async function deleteSourceTree(sourcePath: string): Promise<void> {
+  // Batch the review doc + all findings into a single atomic delete so a
+  // mid-tree crash can't leave the source half-deleted. Legacy migration
+  // handles ~10 docs per PR — well within Firestore's 500-write batch cap.
+  const findingsCol = db.collection(`${sourcePath}/findings`);
+  const findingDocs = await findingsCol.get();
+  if (APPLY) {
+    const batch = db.batch();
+    for (const f of findingDocs.docs) {
+      batch.delete(f.ref);
+    }
+    batch.delete(db.doc(sourcePath));
+    await batch.commit();
+    stats.sourceDeleted++;
+  }
+}
+
+/**
+ * After all reviews under an org-scoped PR are copied, recompute the
+ * denormalised parent-PR fields:
+ *   stats.reviewCount  = number of completed reviews
+ *   latestReviewId     = id of most recently completed review
+ *   hasFindingsMin     = max severity across every finding under every review
+ */
+async function recomputeParentPr(orgId: string, prId: string): Promise<void> {
+  const prRef = db
+    .collection('organizations')
+    .doc(orgId)
+    .collection('pullRequests')
+    .doc(prId);
+
+  const prSnap = await prRef.get();
+  if (!prSnap.exists) {
+    stats.parentPrMissing++;
+    console.warn(`  [parent missing] organizations/${orgId}/pullRequests/${prId} — skipping recompute`);
+    return;
+  }
+
+  const reviewsSnap = await prRef.collection('reviews').get();
+  let reviewCount = 0;
+  let latestCompletedAt: string | null = null;
+  let latestReviewId: string | null = null;
+  let worstSeverity: CodeReviewSeverity | null = null;
+  let worstSeverityOrder = -1;
+
+  // Tally completion stats sequentially (cheap — just iterating in-memory
+  // snapshot data) but fan out finding reads in parallel to avoid the N+1
+  // round-trip pattern of one .get() per review.
+  for (const reviewDoc of reviewsSnap.docs) {
+    const review = reviewDoc.data() as CodeReview;
+    if (review.status === 'completed') {
+      reviewCount++;
+      if (review.completedAt && (!latestCompletedAt || review.completedAt > latestCompletedAt)) {
+        latestCompletedAt = review.completedAt;
+        // Use the Firestore doc key as the source of truth — legacy review
+        // docs may have been written by an older code path that didn't
+        // populate the `id` field inside the document body.
+        latestReviewId = reviewDoc.id;
+      }
+    }
+  }
+
+  const findingsSnaps = await Promise.all(
+    reviewsSnap.docs.map((reviewDoc) => reviewDoc.ref.collection('findings').get()),
+  );
+  for (const findingsSnap of findingsSnaps) {
+    for (const f of findingsSnap.docs) {
+      const finding = f.data() as CodeReviewFinding;
+      const order = CODE_REVIEW_SEVERITY_ORDER[finding.severity];
+      if (order > worstSeverityOrder) {
+        worstSeverity = finding.severity;
+        worstSeverityOrder = order;
+      }
+    }
+  }
+
+  const pr = prSnap.data() as PullRequest;
+  const updates: Record<string, unknown> = {
+    'stats.reviewCount': reviewCount,
+    latestReviewId,
+    hasFindingsMin: worstSeverity,
+    updatedAt: new Date().toISOString(),
+  };
+
+  // Skip the write when nothing actually changes — keeps re-runs noise-free.
+  const currentMin = pr.hasFindingsMin ?? null;
+  const currentLatest = pr.latestReviewId ?? null;
+  const currentReviewCount = pr.stats?.reviewCount ?? null;
+  if (
+    currentReviewCount === reviewCount &&
+    currentLatest === latestReviewId &&
+    currentMin === worstSeverity
+  ) {
+    return;
+  }
+
+  if (APPLY) {
+    await prRef.update(updates);
+    stats.parentPrsRecomputed++;
+  }
+  console.log(
+    `  [recompute] organizations/${orgId}/pullRequests/${prId}: ` +
+      `reviewCount=${currentReviewCount}->${reviewCount}, ` +
+      `latestReviewId=${currentLatest ?? 'null'}->${latestReviewId ?? 'null'}, ` +
+      `hasFindingsMin=${currentMin ?? 'null'}->${worstSeverity ?? 'null'}`,
+  );
+}
+
+async function main(): Promise<void> {
+  console.log(`Backfill mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}${DELETE_SOURCE ? ' (with delete-source)' : ''}`);
+  console.log(`Project: ${PROJECT_ID}`);
+  console.log('');
+
+  // Enumerate the legacy ghost-parents at top-level `pullRequests/{prId}`.
+  //
+  // listDocuments() returns refs for every document path with at least one
+  // subcollection — including "missing" parent docs that were never written
+  // (which is exactly our case: the dead top-level tree's parents never
+  // existed, only their reviews subcollections did).
+  //
+  // This replaces an earlier `db.collectionGroup('reviews').get()` scan
+  // which loaded every review across every org into one snapshot, with no
+  // pagination — fine for the migration's actual scale (~10 docs in prod)
+  // but a footgun if the legacy tree ever held more, since collectionGroup
+  // results are unpaginated by default. listDocuments is bounded by the
+  // top-level collection size (which is the orphaned legacy tree only —
+  // org-scoped subcollections aren't enumerated here).
+  const legacyParentRefs = await db.collection('pullRequests').listDocuments();
+  console.log(`Found ${legacyParentRefs.length} legacy ghost-parent docs at top-level pullRequests/…`);
+
+  const touchedPrs = new Set<string>(); // `${orgId}::${prId}` keys to recompute
+
+  for (const parentRef of legacyParentRefs) {
+    const reviewsCol = parentRef.collection('reviews');
+    const reviewsSnap = await reviewsCol.get();
+    if (reviewsSnap.empty) continue;
+
+    for (const reviewDoc of reviewsSnap.docs) {
+      const path = reviewDoc.ref.path;
+      if (!isLegacyPath(path)) continue; // safety check — should always be legacy under top-level
+
+      stats.reviewsScanned++;
+      const review = reviewDoc.data() as CodeReview;
+      const orgId = review.orgId;
+      const prId = review.prId;
+      const reviewId = review.id;
+
+      if (!orgId || !prId || !reviewId) {
+        console.error(`  [skip] ${path}: missing orgId/prId/id field`);
+        stats.errors++;
+        continue;
+      }
+
+      try {
+        const { copied, alreadyAtTarget } = await copyReview(orgId, prId, reviewId, review);
+        if (alreadyAtTarget) {
+          stats.reviewsAlreadyAtTarget++;
+        } else if (copied) {
+          stats.reviewsCopied++;
+        }
+
+        await copyFindings(orgId, prId, reviewId, path);
+
+        if (DELETE_SOURCE) {
+          await deleteSourceTree(path);
+        }
+
+        touchedPrs.add(`${orgId}::${prId}`);
+        console.log(
+          `  [review] ${path} → organizations/${orgId}/pullRequests/${prId}/reviews/${reviewId}` +
+            (alreadyAtTarget ? ' (already at target)' : copied ? ' (copied)' : ''),
+        );
+      } catch (err) {
+        console.error(`  [error] ${path}: ${(err as Error).message}`);
+        stats.errors++;
+      }
+    }
+  }
+
+  console.log('\nRecomputing denormalised parent PR fields…');
+  for (const key of touchedPrs) {
+    const [orgId, prId] = key.split('::');
+    try {
+      await recomputeParentPr(orgId, prId);
+    } catch (err) {
+      console.error(`  [recompute error] ${key}: ${(err as Error).message}`);
+      stats.errors++;
+    }
+  }
+
+  console.log('\nSummary');
+  console.log('-------');
+  console.log(`  reviews scanned (legacy):     ${stats.reviewsScanned}`);
+  console.log(`  reviews copied:               ${stats.reviewsCopied}`);
+  console.log(`  reviews already at target:    ${stats.reviewsAlreadyAtTarget}`);
+  console.log(`  findings copied:              ${stats.findingsCopied}`);
+  console.log(`  findings already at target:   ${stats.findingsAlreadyAtTarget}`);
+  console.log(`  parent PRs recomputed:        ${stats.parentPrsRecomputed}`);
+  console.log(`  parent PRs missing:           ${stats.parentPrMissing}`);
+  console.log(`  source docs deleted:          ${stats.sourceDeleted}`);
+  console.log(`  errors:                       ${stats.errors}`);
+
+  if (!APPLY) {
+    console.log('\n(dry run — pass --apply to actually write)');
+  }
+  process.exit(stats.errors > 0 ? 1 : 0);
+}
+
+main().catch((err) => {
+  console.error('Fatal:', err);
+  process.exit(2);
+});
