diff --git a/server/services/pull-request-manager.ts b/server/services/pull-request-manager.ts
index 39fcb6471..20a9f47ee 100644
--- a/server/services/pull-request-manager.ts
+++ b/server/services/pull-request-manager.ts
@@ -1,21 +1,26 @@
 /**
  * PullRequestManager — Firestore-backed CRUD for PR lifecycle.
  *
- * Collection paths
- * ----------------
- *   organizations/{orgId}/pullRequests/{prId}  — PullRequest doc (write path)
- *   pullRequests/{prId}                        — CodeReviewPullRequest doc (CRREAD-1 read path)
- *   pullRequests/{prId}/reviews/{reviewId}     — CodeReview doc (CRREAD-1)
- *   pullRequests/{prId}/reviews/{reviewId}/findings/{findingId} — CodeReviewFinding doc (CRREAD-1)
+ * Single-tree storage (the historical CRREAD-1 split between
+ * `organizations/{orgId}/pullRequests` and a top-level `pullRequests` tree was
+ * an aborted refactor — it left writes and reads pointing at different docs
+ * and the dashboard rendered empty. Everything now lives under the org-scoped
+ * tree, matching the rest of this codebase's multi-tenant pattern):
+ *
+ *   organizations/{orgId}/pullRequests/{prId}                                  — PullRequest doc
+ *   organizations/{orgId}/pullRequests/{prId}/reviews/{reviewId}               — CodeReview doc
+ *   organizations/{orgId}/pullRequests/{prId}/reviews/{reviewId}/findings/{id} — CodeReviewFinding doc
  *
  * Document ID convention
  * ----------------------
  *   prId = `{orgId}-{repoFullName.replace('/', '-')}-{number}`
  *   e.g.  "acme-aictrl-dev-aictrl-42"
